ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasActivities ?child ; p:hasLessons ?parent . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Lessons } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?lessonname ?description WHERE {
  ?lessons_activities a :Lessons_Activities .
  ?activities a :Activities .
  ?lessons_activities p:hasActivities ?activities .
  ?lessons a :Lessons .
  ?lessons_activities p:hasLessons ?lessons .
  ?lessons p:lessonName ?lessonname .
  ?activities p:description ?description .
} }
}

